(window.webpackJsonp=window.webpackJsonp||[]).push([[60],{687:function(r,n){r.exports="\x3c!-- \r\ntitle: MySQL\r\nsort: \r\n--\x3e \r\n\r\n# MySQL\r\n\r\n## 安装\r\n\r\n### Debian10\r\n\r\n```bash\r\napt isntall mariadb-server\r\n```\r\n\r\n### Ubuntu+WSL2\r\n\r\n```bash\r\nsudo apt-get install mysql-server \r\nsudo service mysql start\r\nsudo service mysql stop\r\nps -ajx|grep mysql\r\n```\r\n\r\n### Docker\r\n\r\n```bash\r\ndocker pull mariadb\r\ndocker run -d -p 3306:3306 --name mariadb -e MYSQL_ROOT_PASSWORD=root mariadb\r\ndocker exec -it <name>/<cid> bash\r\n```\r\n\r\n### Win\r\n\r\n> `mysqld --initialize --console`\r\n\r\n1. 添加至环境变量\r\n\r\n2. 新建配置文件`my.ini`\r\n\r\n3. ```ini\r\n   [mysql]\r\n   # 设置mysql客户端默认字符集\r\n   default-character-set=utf8\r\n   [mysqld]\r\n   #设置3306端口\r\n   port = 3306\r\n   # 设置mysql的安装目录\r\n   basedir=D:\\App\\mysql-8.0.21-winx64\\\r\n   # 设置mysql数据库的数据的存放目录\r\n   datadir=D:\\App\\mysql-8.0.21-winx64\\data\r\n   # 允许最大连接数\r\n   max_connections=200\r\n   # 服务端使用的字符集默认为8比特编码的latin1字符集\r\n   character-set-server=utf8\r\n   # 创建新表时将使用的默认存储引擎\r\n   default-storage-engine=INNODB\r\n   ```\r\n\r\n4. 生成data文件\r\n\r\n   > 进入data目录\r\n   >\r\n   > `mysqld --initialize-insecure --user=mysql`\r\n\r\n5. 启动服务\r\n\r\n   > 安装服务：`mysqld -install`\r\n   >\r\n   > 开启服务：`net start mysql `\r\n   >\r\n   > 停止服务：`net stop mysql`\r\n   >\r\n   > 卸载服务：`mysqld --remove mysql`\r\n\r\n## 配置\r\n\r\n```bash\r\ncd /etc/mysql/mysql.conf.d/\r\ncat mysqld.conf\r\n```\r\n\r\n### 更换密码\r\n\r\n```bash\r\nmysql -u root -p\r\n\r\n\t\r\n# update mysql.user set authentication_string=password('passwd') where user='root';\r\nset password = '123';\r\n# ERROR 1372 (HY000): Password hash should be a 41-digit hexadecimal number\r\n# 密码是明文，需要用十六进制码\r\nselect password('123')；\r\n+-------------------------------------------+\r\n| password('mysql')                         |\r\n+-------------------------------------------+\r\n| *E74858DB86EBA20BC33D0AECAE8A8108C56B17FA |\r\n+-------------------------------------------+\r\n1 row in set (0.000 sec)\r\n# 重新修改\r\nset password='*E74858DB86EBA20BC33D0AECAE8A8108C56B17FA';\r\n\r\nflush privileges;  #立即生效\r\n```\r\n\r\n### 其他\r\n\r\n```mysql\r\n# 选择要使用的数据库\r\nuse mysql;\r\n# 查询用户\r\nselect User from user;\r\n# 开启远程访问\r\nupdate user set host = '%' where user = 'root';\t\t\r\n```\r\n\r\n"}}]);